hitMacro.command:
const SIZES = ["small", "medium", "large", "huge", "giant", "colossal"];
const MODES = CONST.ACTIVE_EFFECT_CHANGE_TYPES ?? CONST.ACTIVE_EFFECT_MODES;
const tgts = (typeof targets !== "undefined" && targets?.length)
  ? targets
  : Array.from(game.user.targets);
if (!tgts.length) return ui.notifications.warn("No token targeted.");

for (const t of tgts) {
  if (t.actor.effects.some(e => e.name === "Shrink")) continue;
  const cur = t.actor.system.size || "medium";
  const smaller = SIZES[Math.max(0, SIZES.indexOf(cur) - 1)];
  const changes = [
    { key: "system.size", mode: MODES.OVERRIDE, value: smaller, priority: 20 },
    { key: "system.spellDamageDieSizeBonus", mode: MODES.ADD, value: "-2", priority: 20 },
  ];
  for (const k of Object.keys(CONFIG.VAGABOND.weaponSkills)) {
    changes.push({ key: `system.${k}DamageDieSizeBonus`, mode: MODES.ADD, value: "-2", priority: 20 });
  }
  await t.actor.createEmbeddedDocuments("ActiveEffect", [{
    name: "Shrink",
    img: "icons/magic/control/energy-stream-link-blue.webp",
    changes,
  }]);
}

//ui.notifications.info(`Shrink applied to ${tgts.length} target(s).`);
